import React, { useEffect, useState } from "react";
import axios from "axios";
import Swal from "sweetalert2";
import { useNavigate } from "react-router-dom";
import { ArrowLeftIcon } from "@heroicons/react/24/solid";
import { motion } from "framer-motion";

export default function EditProfile() {
  const navigate = useNavigate();

  const [user, setUser] = useState(null);
  const [name, setName] = useState("");
  const [imageFile, setImageFile] = useState(null);
  const [preview, setPreview] = useState("");

  const [currentPassword, setCurrentPassword] = useState("");
  const [newPassword, setNewPassword] = useState("");

  const stored = JSON.parse(localStorage.getItem("user") || "{}");
  const role = (stored?.role || "").toLowerCase();

  const getUpdateUrl = () => {
    if (role === "admin")
      return "http://localhost:8086/user/admin/update-profile";
    if (role.includes("academic"))
      return "http://localhost:8086/user/academic/update-profile";
    return "http://localhost:8086/user/update-profile";
  };

  useEffect(() => {
    if (!stored?.email) {
      navigate("/");
      return;
    }

    axios
      .get("http://localhost:8086/user/profile", {
        params: { email: stored.email },
      })
      .then((res) => {
        setUser(res.data);
        setName(res.data.name);
        setPreview(res.data.profileImage);
      })
      .catch(() => {
        Swal.fire("Error", "Failed to load profile", "error");
      });
  }, [navigate, stored?.email]);

  const handleImageChange = (e) => {
    const file = e.target.files[0];
    if (!file) return;

    setImageFile(file);

    const reader = new FileReader();
    reader.onloadend = () => setPreview(reader.result);
    reader.readAsDataURL(file);
  };

  const handleUpdateProfile = async () => {
    try {
      const formData = new FormData();
      formData.append("email", user.email);
      formData.append("name", name);
      if (imageFile) formData.append("image", imageFile);

      const res = await axios.put(getUpdateUrl(), formData);

      Swal.fire("Success", "Profile updated", "success").then(() => {
        localStorage.setItem("user", JSON.stringify(res.data));
        navigate(-1);
      });
    } catch (err) {
      Swal.fire("Error", "Update failed", "error");
    }
  };

  const handleChangePassword = async () => {
    if (!currentPassword || !newPassword) {
      Swal.fire("Warning", "Fill all password fields", "warning");
      return;
    }

    try {
      const res = await axios.put(
        "http://localhost:8086/user/change-password",
        {
          email: user.email,
          currentPassword,
          newPassword,
        }
      );

      Swal.fire("Success", res.data.message, "success");
      setCurrentPassword("");
      setNewPassword("");
    } catch {
      Swal.fire("Error", "Password update failed", "error");
    }
  };

  if (!user) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-indigo-50 to-purple-100">
        <div className="text-gray-600 animate-pulse">Loading editor...</div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex justify-center bg-gradient-to-br from-indigo-50 via-white to-purple-50 p-6">

      <div className="w-full max-w-5xl">

        {/* HEADER */}
        <div className="mb-6">

          {/* BACK BUTTON WITH SMOOTH ANIMATION */}
          <motion.button
            onClick={() => navigate(-1)}
            initial={{ opacity: 0, x: -10 }}
            animate={{ opacity: 1, x: 0 }}
            whileHover={{ scale: 1.1, x: -3 }}
            whileTap={{ scale: 0.95 }}
            transition={{ type: "spring", stiffness: 300 }}
            className="flex items-center gap-2 mb-4 px-3 py-2 rounded-xl bg-white shadow hover:shadow-md transition"
          >
            <ArrowLeftIcon className="w-5 h-5 text-gray-700" />
            <span className="text-sm text-gray-700 font-medium">
              Back
            </span>
          </motion.button>

          <h1 className="text-3xl font-bold text-gray-800">
            Edit Profile
          </h1>
          <p className="text-gray-500 text-sm">
            Update your {role || "user"} account settings
          </p>
        </div>

        {/* MAIN CARD */}
        <motion.div
          initial={{ opacity: 0, y: 15 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.4 }}
          className="bg-white/70 backdrop-blur-lg rounded-3xl shadow-xl border border-white/40 overflow-hidden"
        >
          <div className="grid grid-cols-1 md:grid-cols-3">

            {/* LEFT */}
            <div className="bg-gray-50/60 p-8 flex flex-col items-center border-r border-gray-100">

              <img
                src={
                  preview ||
                  `https://ui-avatars.com/api/?name=${user.username}`
                }
                className="w-32 h-32 rounded-full object-cover border-4 border-indigo-500 shadow-md"
                alt="Profile"
              />

              <h3 className="mt-4 font-semibold text-gray-800 text-lg">
                {user.name}
              </h3>
              <p className="text-sm text-gray-500">{user.role}</p>

              <label className="mt-6 text-sm font-medium text-indigo-600 cursor-pointer hover:underline">
                Change Photo
                <input
                  type="file"
                  hidden
                  accept="image/*"
                  onChange={handleImageChange}
                />
              </label>

              <button
                onClick={handleUpdateProfile}
                className="mt-8 w-full bg-indigo-600 text-white py-2.5 rounded-xl shadow hover:bg-indigo-700 hover:scale-[1.02] transition"
              >
                Save Profile
              </button>
            </div>

            {/* RIGHT */}
            <div className="md:col-span-2 p-8 space-y-8">

              {/* BASIC */}
              <div>
                <h3 className="text-lg font-bold text-gray-800 mb-4">
                  Basic Information
                </h3>

                <input
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  className="w-full p-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                />
              </div>

              {/* SECURITY */}
              <div className="border-t pt-6 border-gray-100">

                <h3 className="text-lg font-bold text-gray-800 mb-4">
                  Security
                </h3>

                <div className="space-y-4">

                  <input
                    type="password"
                    placeholder="Current Password"
                    value={currentPassword}
                    onChange={(e) => setCurrentPassword(e.target.value)}
                    className="w-full p-3 bg-gray-50 border rounded-xl focus:ring-2 focus:ring-pink-500 outline-none"
                  />

                  <input
                    type="password"
                    placeholder="New Password"
                    value={newPassword}
                    onChange={(e) => setNewPassword(e.target.value)}
                    className="w-full p-3 bg-gray-50 border rounded-xl focus:ring-2 focus:ring-pink-500 outline-none"
                  />

                  <button
                    onClick={handleChangePassword}
                    className="w-full bg-pink-500 text-white py-2.5 rounded-xl hover:bg-pink-600 hover:scale-[1.02] transition"
                  >
                    Update Password
                  </button>

                </div>
              </div>

            </div>
          </div>
        </motion.div>
      </div>
    </div>
  );
}
